#include <map>
#include <string>
#include <string_view>
#include <vector>

namespace ftxui::ui {

/// @brief A geographic coordinate (longitude/latitude in degrees).
struct GeoPoint {
  double lon = 0;
  double lat = 0;
};

/// @brief A closed ring of geographic points (exterior/interior polygon ring).
using GeoRing = std::vector<GeoPoint>;

/// @brief Raw geometry from a GeoJSON feature (Point, LineString, Polygon, etc.).
struct GeoGeometry {
  std::string type;
  std::vector<GeoPoint> points;
  std::vector<GeoRing> rings;
  std::vector<std::vector<GeoRing>> multipolygon;
};

/// @brief A single GeoJSON feature with geometry and key/value properties.
struct GeoFeature {
  GeoGeometry geometry;
  std::map<std::string, std::string> properties;
  std::string name() const;
};

/// @brief A parsed GeoJSON FeatureCollection with pre-computed bounds.
struct GeoCollection {
  std::vector<GeoFeature> features;
  double min_lon = 180;
  double max_lon = -180;
  double min_lat = 90;
  double max_lat = -90;
  /// @brief Recompute min/max lon/lat from all features.
  void ComputeBounds();
};

/// @brief Parse a GeoJSON string into a GeoCollection.
GeoCollection ParseGeoJSON(std::string_view json);
/// @brief Load a GeoJSON file from disk into a GeoCollection.
GeoCollection LoadGeoJSON(std::string_view path);

}  // namespace ftxui::ui

// ---- ftxui/ui/geomap.hpp ----
// Copyright 2024 Arthur Sonzogni. All rights reserved.
// Use of this source code is governed by the MIT license that can be found in
// the LICENSE file.
#include <functional>
#include <memory>
#include <string_view>

// [amalgamated] #include "ftxui/component/component.hpp"
// [amalgamated] #include "ftxui/screen/color.hpp"
// [amalgamated] #include "ftxui/ui/geojson.hpp"

namespace ftxui::ui {

enum class Projection {
  Equirectangular,
  Mercator,
};

/// @brief Terminal map renderer for GeoJSON data using braille Canvas.
///
/// @code
/// auto collection = ui::LoadGeoJSON("world.geojson");
/// auto map = ui::GeoMap()
///     .Data(collection)
///     .SetProjection(Projection::Mercator)
///     .LineColor(Color::Green)
///     .ShowGraticule(true)
///     .Overlay(cities, Color::Yellow)           // city markers
///     .AddArc(-77, 38.9, 37.6, 55.75, Color::Red) // missile arc DC→Moscow
///     .OnSelect([](const GeoFeature& f){ /* ... */ })
///     .Build();
/// @endcode
class GeoMap {
 public:
  GeoMap();

  GeoMap& Data(const GeoCollection& col);
  GeoMap& Data(std::string_view geojson_str);
  GeoMap& LoadFile(std::string_view path);

  GeoMap& SetProjection(Projection p);
  GeoMap& PointColor(ftxui::Color c);
  GeoMap& LineColor(ftxui::Color c);
  GeoMap& FillColor(ftxui::Color c);
  GeoMap& ShowGraticule(bool v = true);
  GeoMap& GraticuleStep(float degrees = 30.0f);
  GeoMap& OnSelect(std::function<void(const GeoFeature&)> fn);

  /// Draw an additional GeoCollection on top of the base map with a
  /// custom color.  Call multiple times to stack overlays.
  GeoMap& Overlay(const GeoCollection& col, ftxui::Color color);

  /// Draw a great-circle arc between two (lon,lat) positions.
  /// @param steps  number of interpolation segments (default 32)
  GeoMap& AddArc(double lon1,
                 double lat1,
                 double lon2,
                 double lat2,
                 ftxui::Color color,
                 int steps = 32);

  ftxui::Component Build();

 private:
  struct Impl;
  std::shared_ptr<Impl> impl_;
};

}  // namespace ftxui::ui

