#include <memory>   // for make_shared, __shared_ptr_access
#include <utility>  // for move

// [amalgamated] #include "ftxui/dom/elements.hpp"  // for Element, unpack, filler, flex, flex_grow, flex_shrink, notflex, xflex, xflex_grow, xflex_shrink, yflex, yflex_grow, yflex_shrink
