// [amalgamated] #include "ftxui/dom/elements.hpp"        // for Element, strikethrough
// [amalgamated] #include "ftxui/dom/node.hpp"            // for Node
#include "ftxui/dom/node_decorator.hpp"  // for NodeDecorator
// [amalgamated] #include "ftxui/screen/box.hpp"          // for Box
// [amalgamated] #include "ftxui/screen/screen.hpp"       // for Cell, Screen

namespace ftxui {

/// @brief Apply a strikethrough to text.
/// @ingroup dom
Element strikethrough(Element child) {
  class Impl : public NodeDecorator {
   public:
    using NodeDecorator::NodeDecorator;

    void Render(Screen& screen) override {
      for (int y = box_.y_min; y <= box_.y_max; ++y) {
        for (int x = box_.x_min; x <= box_.x_max; ++x) {
          screen.CellAt(x, y).strikethrough = true;
        }
      }
      Node::Render(screen);
    }
  };

  return std::make_shared<Impl>(std::move(child));
}

}  // namespace ftxui

