#include <ftxui/dom/direction.hpp>  // for Direction, Direction::Down, Direction::Left, Direction::Right, Direction::Up
#include <functional>               // for function
#include <string>                   // for operator+, string
#include <utility>                  // for move
#include <vector>                   // for vector, __alloc_traits<>::value_type

// [amalgamated] #include "ftxui/component/animation.hpp"  // for Animator, Linear
// [amalgamated] #include "ftxui/component/app.hpp"        // for Component
// [amalgamated] #include "ftxui/component/component.hpp"  // for Make, Menu, MenuEntry, Toggle
// [amalgamated] #include "ftxui/component/component_base.hpp"     // for ComponentBase
// [amalgamated] #include "ftxui/component/component_options.hpp"  // for MenuOption, MenuEntryOption, UnderlineOption, AnimatedColorOption, AnimatedColorsOption, EntryState
// [amalgamated] #include "ftxui/component/event.hpp"  // for Event, Event::ArrowDown, Event::ArrowLeft, Event::ArrowRight, Event::ArrowUp, Event::End, Event::Home, Event::PageDown, Event::PageUp, Event::Return, Event::Tab, Event::TabReverse
// [amalgamated] #include "ftxui/component/mouse.hpp"  // for Mouse, Mouse::Left, Mouse::Released, Mouse::WheelDown, Mouse::WheelUp, Mouse::None
// [amalgamated] #include "ftxui/dom/elements.hpp"  // for operator|, Element, reflect, Decorator, nothing, Elements, bgcolor, color, hbox, separatorHSelector, separatorVSelector, vbox, xflex, yflex, text, bold, focus, inverted, select
// [amalgamated] #include "ftxui/screen/box.hpp"    // for Box
