#include <functional>
#include <memory>
#include <string>
#include <utility>
#include <vector>

// [amalgamated] #include "ftxui/component/component.hpp"
// [amalgamated] #include "ftxui/component/component_options.hpp"
// [amalgamated] #include "ftxui/component/event.hpp"
